const input = items[0].json;
const response = input.output || '';

let nutrition = {
  source: 'ai',
  found: false,
  calories: 0,
  protein_g: 0,
  carbs_g: 0,
  fat_g: 0,
  fiber_g: 0,
  sugar_g: 0,
  sodium_mg: 0,
  confidence: 'low'
};

try {
  let cleaned = response
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();

  const parsed = JSON.parse(cleaned);
  nutrition = {
    source: 'ai',
    found: true,
    ...parsed
  };
} catch (e) {
  console.log('Parse error:', e.message);
}

return { json: nutrition };

const allData = items.map(i => i.json);
const trigger = $('When Executed by Another Workflow').first().json;

let apiNinjas = allData.find(d => d.source === 'api-ninjas') || { found: false, calories: 0 };
let aiEstimate = allData.find(d => d.source === 'ai') || { found: false, calories: 0 };

const mealName = trigger.meal_name;

let result = {
  meal_name: mealName,
  calories: 0,
  protein_g: 0,
  carbs_g: 0,
  fat_g: 0,
  fiber_g: 0,
  sugar_g: 0,
  sodium_mg: 0,
  confidence: 'low',
  source: 'default',
  notes: ''
};

const apiFound = apiNinjas.found && apiNinjas.calories > 0;
const aiFound = aiEstimate.found && aiEstimate.calories > 0;

if (apiFound && aiFound) {
  const diff = Math.abs(apiNinjas.calories - aiEstimate.calories);
  const avg = (apiNinjas.calories + aiEstimate.calories) / 2;
  const diffPct = (diff / avg) * 100;

  if (diffPct < 20) {
    result.calories = Math.round(avg);
    result.protein_g = Math.round((apiNinjas.protein_g + aiEstimate.protein_g) / 2);
    result.carbs_g = Math.round((apiNinjas.carbs_g + aiEstimate.carbs_g) / 2);
    result.fat_g = Math.round((apiNinjas.fat_g + aiEstimate.fat_g) / 2);
    result.fiber_g = Math.round((apiNinjas.fiber_g + aiEstimate.fiber_g) / 2);
    result.sugar_g = Math.round((apiNinjas.sugar_g + aiEstimate.sugar_g) / 2);
    result.sodium_mg = Math.round((apiNinjas.sodium_mg + aiEstimate.sodium_mg) / 2);
    result.confidence = 'high';
    result.source = 'combined';
    result.notes = 'Sources agree within 20%';
  } else if (diffPct < 40) {
    result.calories = Math.round(apiNinjas.calories * 0.6 + aiEstimate.calories * 0.4);
    result.protein_g = Math.round(apiNinjas.protein_g * 0.6 + aiEstimate.protein_g * 0.4);
    result.carbs_g = Math.round(apiNinjas.carbs_g * 0.6 + aiEstimate.carbs_g * 0.4);
    result.fat_g = Math.round(apiNinjas.fat_g * 0.6 + aiEstimate.fat_g * 0.4);
    result.fiber_g = Math.round(apiNinjas.fiber_g * 0.6 + aiEstimate.fiber_g * 0.4);
    result.sugar_g = Math.round(apiNinjas.sugar_g * 0.6 + aiEstimate.sugar_g * 0.4);
    result.sodium_mg = Math.round(apiNinjas.sodium_mg * 0.6 + aiEstimate.sodium_mg * 0.4);
    result.confidence = 'medium';
    result.source = 'combined';
    result.notes = 'Sources differ by ' + Math.round(diffPct) + '%';
  } else {
    if (apiNinjas.calories > 50 && apiNinjas.calories < 2000) {
      Object.assign(result, apiNinjas);
      result.confidence = 'medium';
      result.notes = 'Large disagreement, using API-Ninjas';
    } else {
      Object.assign(result, aiEstimate);
      result.confidence = 'low';
      result.notes = 'Large disagreement, using AI';
    }
  }
} else if (apiFound) {
  Object.assign(result, apiNinjas);
  result.confidence = 'medium';
  result.notes = 'API-Ninjas only';
} else if (aiFound) {
  Object.assign(result, aiEstimate);
  result.notes = 'AI estimate only';
} else {
  result.calories = 200;
  result.protein_g = 5;
  result.carbs_g = 25;
  result.fat_g = 8;
  result.notes = 'No data available, using defaults';
}

delete result.found;
result.meal_name = mealName;

return { json: result };

const response = items[0].json;

// API-Ninjas returns array directly, not nested in 'items'
const apiItems = Array.isArray(response) ? response : (response.items || []);

if (apiItems.length === 0) {
  return {
    json: {
      source: 'api-ninjas',
      found: false,
      calories: 0,
      protein_g: 0,
      carbs_g: 0,
      fat_g: 0,
      fiber_g: 0,
      sugar_g: 0,
      sodium_mg: 0
    }
  };
}

const totals = {
  source: 'api-ninjas',
  found: true,
  calories: 0,
  protein_g: 0,
  carbs_g: 0,
  fat_g: 0,
  fiber_g: 0,
  sugar_g: 0,
  sodium_mg: 0
};

for (const item of apiItems) {
  totals.calories += item.calories || 0;
  totals.protein_g += item.protein_g || 0;
  totals.carbs_g += item.carbohydrates_total_g || 0;
  totals.fat_g += item.fat_total_g || 0;
  totals.fiber_g += item.fiber_g || 0;
  totals.sugar_g += item.sugar_g || 0;
  totals.sodium_mg += item.sodium_mg || 0;
}

return { json: totals };

const dbItem = items[0].json;
const trigger = $('When Executed by Another Workflow').first().json;

return {
  json: {
    meal_name: trigger.meal_name,
    calories: dbItem.calories,
    protein_g: dbItem.protein_g || 0,
    carbs_g: dbItem.carbs_g || 0,
    fat_g: dbItem.fat_g || 0,
    fiber_g: dbItem.fiber_g || 0,
    sugar_g: dbItem.sugar_g || 0,
    sodium_mg: dbItem.sodium_mg || 0,
    confidence: dbItem.confidence || 'medium',
    source: 'universal_db',
    notes: 'From verified database (' + (dbItem.verification_count || 0) + ' verifications)'
  }
};
